import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"13. Pharmacist Weekend Ordinary Hours","description":"","frontmatter":{"title":"13. Pharmacist Weekend Ordinary Hours","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["schedules","hours","pay-rates"]},"headers":[],"relativePath":"ebas/mspp/schedules/13-pharmacist-weekend-ordinary-hours.md","filePath":"ebas/mspp/schedules/13-pharmacist-weekend-ordinary-hours.md"}'),i={name:"ebas/mspp/schedules/13-pharmacist-weekend-ordinary-hours.md"};function r(s,e,l,h,d,p){return o(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="_13-pharmacist-weekend-ordinary-hours" tabindex="-1">13. Pharmacist Weekend Ordinary Hours <a class="header-anchor" href="#_13-pharmacist-weekend-ordinary-hours" aria-label="Permalink to &quot;13. Pharmacist Weekend Ordinary Hours&quot;">​</a></h1><p>Formatting note</p><p>The schedule body below is rendered in a monospaced block to preserve the column layout of pay tables and classification grids. The block is excluded from the search index so search results stay short; find schedules by their title, number, topic or synonyms.</p><p>\`\`\`text AND ASSOCIATED ENTITLEMENTS – AUSTIN HEALTH, EASTERN HEALTH, ALFRED HEALTH, PETER MACCALLUM CANCER INSTITUTE, ROYAL VICTORIAN EYE AND EAR HOSPITAL, MELBOURNE HEALTH, WESTERN HEALTH, NORTHERN HEALTH, ROYAL WOMEN’S HO</p><p>ENTITLEMENTS – AUSTIN HEALTH, EASTERN HEALTH, ALFRED HEALTH, PETER MACCALLUM CANCER INSTITUTE, ROYAL VICTORIAN EYE AND EAR HOSPITAL, MELBOURNE HEALTH, WESTERN HEALTH, NORTHERN HEALTH, ROYAL WOMEN’S HO</p><ol><li><p>Royal Women’s Hospital and The Royal Children’s Hospital 3.1 Redundancy (a) Where the Health Service have made a definite decision that they no longer wish the work the Employee has been doing, to be done by anyone, and that decision may lead to termination of employment, they shall hold discussions in accordance with clause 30 of this Agreement with the Employees directly affected and, their representatives which may include the Union. This will apply where the possible termination is not due to the ordinary and customary turnover of labour. (b) Where redeployment opportunities do not exist and an Employee is made compulsorily redundant, they will receive the following :</p><pre><code>      (i)      A payment calculated as per Victorian Government policy for
               Targeted Separation Packages as at the time of termination.
               (A)      calculation of continuous service shall be the same as for
                        Long Service Leave under this Agreement;.
               (B)      provision for independent financial counselling;
               (C)      job search services including one day per week without
                        loss of pay for the purpose of seeking other employment
                        during the period of notice. The time off shall be taken at
                        a time that is convenient to the Employee after
                        consultation with the Employer.
      (ii)     If the Employee has been allowed paid leave for more than one day
               during the notice period for the purpose of seeking other
               employment, the Employee shall, at the request of the Employer,
               be required to produce proof of attendance at an interview or they
               shall not receive payment for the time absent.
</code></pre><p>(c) provision of in-house training in preparing a curriculum vitae.</p><p>(d) Upon the cessation of employment the Health Service will supply a statement to the Employee consisting of an employment history including: the period of employment, classification, accrued entitlements and job description.</p><p>(e) Where redeployment opportunities do not exist and an Employee is made compulsorily redundant, they will receive:</p><pre><code>      (i)      job search services including one day per week without loss of pay
               for the purpose of seeking other employment during the period of
               notice. The time off shall be taken at a time that is convenient to the
               Employee after consultation with the Employer.
</code></pre><p>(f) If the Employee has been allowed paid leave for more than one day during the notice period for the purpose of seeking other employment, the Employee shall, at the request of the Employer, be required to produce proof of attendance at an interview or they shall not receive payment for the time absent. AND ASSOCIATED ENTITLEMENTS – AUSTIN HEALTH, EASTERN HEALTH, ALFRED HEALTH, PETER MACCALLUM CANCER INSTITUTE, ROYAL VICTORIAN EYE AND EAR HOSPITAL, MELBOURNE HEALTH, WESTERN HEALTH, NORTHERN HEALTH, ROYAL WOMEN’S HO</p></li></ol><p>ENTITLEMENTS – AUSTIN HEALTH, EASTERN HEALTH, ALFRED HEALTH, PETER MACCALLUM CANCER INSTITUTE, ROYAL VICTORIAN EYE AND EAR HOSPITAL, MELBOURNE HEALTH, WESTERN HEALTH, NORTHERN HEALTH, ROYAL WOMEN’S HO</p><pre><code>   (g)     Nothing in this Agreement shall prevent an Employee from applying for a
           Voluntary Departure Package however titled which shall be calculated in line
           with Victorian Government policy on Voluntary Departure Packages.
</code></pre><ol><li><p>Monash Health 4.1 Unexpired Portion of Redeployment Period An Employee who has elected to discontinue a period of redeployment shall be entitled to a lump sum amount equal to the unexpired portion of the redeployment period. 4.2 WorkCover Where a position has been declared redundant whilst an affected Employee is subject to a WorkCover claim, the following procedures shall apply: (a) Rehabilitation An injured Employee shall be assessed for rehabilitation into a suitable position and a Reasonable Offer made. The Health Service shall require the treating medical practitioner to provide a certificate indicating the degree of capacity of the Employee to perform pre-injury or modified duties. (b) Entitlement to Departure Package The right of a claimant who has an existing Work Cover claim to be eligible for a departure package, will be determined by the Health Service. (c) Effect of Departure Package on Work Cover Claims The Work Cover entitlement of a claimant who takes a departure package will be governed by the provisions of the Workplace Injury Rehabilitation and Compensation Act 2013 (Vic). One visit will be made available for the affected Employee to have an independent financial counselling. Such costs will be borne by the Employer.</p></li><li><p>St. Vincent’s Hospital 5.1 Consultation Principles (a) It is acknowledged that the intent of the consultative process is to facilitate the co-operative introductions of change, where this is found to be warranted and that agreement to facilitate this should not be withheld unreasonably. (b) No change will be implemented which has negative impact upon the employment of Employees without the parties first exploring ways in which to eliminate or lessen such negative impact.</p><p>(c) No Employee will lose their job or have their award classification or number of ordinary hours of work per week reduced except by consultation and agreement. (d) No Employee will be transferred or moved to another job or department without the provision of appropriate training and consultation and agreement as to the manner in which this will occur.</p></li></ol><p>AND ASSOCIATED ENTITLEMENTS – AUSTIN HEALTH, EASTERN HEALTH, ALFRED HEALTH, PETER MACCALLUM CANCER INSTITUTE, ROYAL VICTORIAN EYE AND EAR HOSPITAL, MELBOURNE HEALTH, WESTERN HEALTH, NORTHERN HEALTH, ROYAL WOMEN’S HO</p><p>ENTITLEMENTS – AUSTIN HEALTH, EASTERN HEALTH, ALFRED HEALTH, PETER MACCALLUM CANCER INSTITUTE, ROYAL VICTORIAN EYE AND EAR HOSPITAL, MELBOURNE HEALTH, WESTERN HEALTH, NORTHERN HEALTH, ROYAL WOMEN’S HO</p><pre><code>   (e)    No Employee will have their job description, responsibilities or duties
          amended without consultation.
   (f)    Any dispute arising out of this agreement shall be immediately referred to
          Health Service management and employee representatives, which may
          include the Union, for prompt resolution.
   (g)    No recommendation agreed to will be implemented where the change
          recommended impacts upon any work group without those other work
          groups first having been consulted by Hospital management and the working
          parties.
   (h)    No Employee will be required to perform work outside the tasks, functions
          and responsibilities that would normally be performed by that specific
          classification of employment without consultation and agreement with the
          Employees and their representatives which may include the Union .
</code></pre><p>5.2 Change Consultation Process (a) No change will be implemented which has a negative impact upon the employment of Employees without the parties first exploring ways in which to eliminate or lessen such negative impact.</p><pre><code>   (b)    No Employee will lose their job or have their classification or number or
          ordinary hours of work per week reduced except by consultation.
   (c)    No Employee will be transferred or moved to another job or department
          without the provision of appropriate training and consultation as to the
          manner in which this will occur.
   (d)    No Employee will have their job description, responsibilities or duties
          amended without consultation.

   (e)    No Employee will be required to perform work outside the tasks, functions
          and responsibilities that would normally be performed by that specific
          classification of employment without consultation with Employees and the
          Employee representatives, which may include the Union.
</code></pre><p>5.3 Redundancy and Redeployment Implementation (a) Where a position has been declared redundant by the Employer at a date and time specified by the Employer and alternative redeployment opportunities have not been identified by the Employer by the end of the redeployment period, the Affected Employee shall be offered separation payments in accordance with clause 32.6(a) .</p><pre><code>   (b)    where an Employee whose position has been declared redundant elects to
          discontinue the 13-week redeployment period provided for by this clause,
          they shall be entitled, in addition to all other entitlements, to a lump sum
          payment equal to the unexpired portion of the redeployment period.
</code></pre><p>AND ASSOCIATED ENTITLEMENTS – AUSTIN HEALTH, EASTERN HEALTH, ALFRED HEALTH, PETER MACCALLUM CANCER INSTITUTE, ROYAL VICTORIAN EYE AND EAR HOSPITAL, MELBOURNE HEALTH, WESTERN HEALTH, NORTHERN HEALTH, ROYAL WOMEN’S HO</p><p>ENTITLEMENTS – AUSTIN HEALTH, EASTERN HEALTH, ALFRED HEALTH, PETER MACCALLUM CANCER INSTITUTE, ROYAL VICTORIAN EYE AND EAR HOSPITAL, MELBOURNE HEALTH, WESTERN HEALTH, NORTHERN HEALTH, ROYAL WOMEN’S HO</p><p>5.4 Retraining (a) Retraining may be granted by the Employer if it is considered that an affected Employee&#39;s opportunity for redeployment would be significantly increased by undertaking such training. (b) Where retraining opportunities are available, the following principles shall apply:</p><pre><code>           (i)          if internal training is undertaken by an affected Employee in a
                        redeployment situation, any associated training costs shall be met
                        by the affected Employees’ previous department.
           (ii)         if external training is undertaken by an affected Employee in a
                        redeployment situation the costs shall be met by the employer.
           (iii)        during the retraining period, income will be maintained in
                        accordance with clause 32.4b of this agreement.
           (iv)         retraining shall be provided to the extent that it would normally be
                        provided to any new employee in that position.
</code></pre><p>5.5 Financial Counselling Employees reserve the right to seek private financial counselling and shall accept responsibility for any professional fees that occur. The Employer agrees to pay a cost up to $300 to an affected Employee. A receipt to be provided before any reimbursement is made. 5.6 WorkCover similar comment to above Where a position has been declared redundant whilst an affected Employee is subject to a WorkCover claim, the following procedures shall apply: (a) Rehabilitation An injured Employee shall be assessed for rehabilitation into a suitable position and a Reasonable Offer made. The Employer shall require the treating medical practitioner to provide a certificate indicating the degree of capacity of the Employee to perform pre-injury or modified duties. 5.7 Entitlement to Departure Package The right of a claimant who has an existing Work Cover claim to be eligible for a departure package, will be determined in accordance with state government policy. 5.8 Effect of Departure Package on Work Cover Claims The Work Cover entitlement of a claimant who takes a departure package will be governed by the provisions of the Workplace Injury Rehabilitation and Compensation Act 2013 (Vic).</p><p>AND ASSOCIATED ENTITLEMENTS – AUSTIN HEALTH, EASTERN HEALTH, ALFRED HEALTH, PETER MACCALLUM CANCER INSTITUTE, ROYAL VICTORIAN EYE AND EAR HOSPITAL, MELBOURNE HEALTH, WESTERN HEALTH, NORTHERN HEALTH, ROYAL WOMEN’S HO</p><p>HOURS 1. Purpose The purpose of this Schedule is to provide Agreement provisions to enable a Pharmacist including an Intern and Student Pharmacist, to work ordinary hours outside the limitation prescribed in clause 55. 2. Commencement Date This Schedule shall operate from 1 July 2023. 3. Definitions For the purposes of this Schedule, the following terms are defined as follows: (a) Pharmacist means a Pharmacist, Intern or Student Pharmacist. (b) A ‘new Pharmacist’ for the purposes of clause 5 is a Pharmacist who commences employment with an employer listed in Schedule 1 after 1 March 2023. (c) Weekend Roster or Weekend Rostering means the working of ordinary hours on a Saturday and/or Sunday.</p><pre><code>     (d)      Weekend means Saturday and/or Sunday.
</code></pre><ol><li><p>Process for a Pharmacist to opt -in to a Weekend Ordinary Hours Roster for existing Pharmacists (a) A Pharmacist may choose to work any part of their ordinary weekly hours on a weekend in accordance with the following:</p><pre><code>          (i)        A Pharmacist, who commenced employment with an Employer
                     listed in Schedule 1 prior to 1/03/2023 can request an arrangement
                     to work ordinary hours on a Saturday or Sunday made in
                     accordance with this Schedule. The employer may agree to such a
                     request, providing that the details of the weekend rostering
                     arrangement are agreed between the employee and the employer.
          (ii)       Where an arrangement is agreed in accordance with sub-clause
                     4(a)(i), Attachment 1 of this Schedule must be used. Any
                     arrangement of rostering ordinary hours on a weekend that does
                     not comply with the provisions of this Schedule is a breach of clause
                     55 Hours of Work.
          (iii)      An employer cannot request or direct a Pharmacist to work an
                     ordinary hours on a weekend roster.
</code></pre><p>Example Where an all-staff communication is provided to existing Pharmacists so as to ascertain interest in working ordinary hours on the weekend, an Employer will not be considered to be requesting or directing an employee to work ordinary hours on a weekend roster. (iv) A Pharmacist may withdraw from a Pharmacist Ordinary Hours on a Weekend Roster Agreement by giving 28 days’ notice to their Employer.</p><pre><code>       (v)        A Pharmacist who withdraws from a Pharmacist Ordinary Hours on
                  a Weekend Roster Agreement will immediately be rostered in
                  accordance with clause 55 (Hours of Work) of this Agreement from
                  the date of next posted roster, providing the commencement of the
                  next posted roster is not greater than 14 days from the 28 days’
                  notice date.
       (vi)       A Pharmacist who withdraws from a Pharmacist Ordinary Hours on
                  a Weekend Roster Agreement can request at any time afterwards
                  another ordinary hours on a weekend roster. If agreed by the
                  Employer, the rostering arrangements shall be compliant with the
                  provisions of this Schedule, including using Attachment 1.
       (vii)      The Monday to Friday hours of a Pharmacist that are worked on a
                  weekend as a result of a roster made under this Schedule will be
                  filled immediately in accordance with existing internal processes,
                  which may include clause 34.
       (viii)     The provisions of clause 57.4 Rostering Protocols and 61.8
                  Weekend Shift Worker Additional Leave will apply to a Pharmacist
                  who works ordinary hours on a weekend roster arrangement.
       (ix)       A roster made under this Schedule must be safe.
</code></pre><ol><li><p>New Pharmacist Employees (a) The following provisions apply to a new Pharmacist:</p><pre><code>   (i)        An employer can roster ordinary hours of a new Pharmacist (as
              defined) on a weekend ordinary hours roster after the new
              Pharmacist has completed appropriate training and/or orientation,
              which may take up to three (3) months to complete.
   (ii)       The rostering arrangements for the new Pharmacist will be
              determined and executed in accordance with the provisions of this
   (iii)      Following 12 months of being rostered to work the weekend roster,
              a new Pharmacist rostered to work ordinary hours on a weekend
              can opt out of the Pharmacist Ordinary Hours on a Weekend Roster
              Agreement with 28 days’ notice to the employer. The opt out
              arrangement for a new Pharmacist shall be in accordance with
              clause 4(a)(v) and 4(a)(vi)of this Schedule.
   (iv)       Where there are genuine operational concerns relating to the timing
              of a new Pharmacists’ withdrawal from a Pharmacist Ordinary
              Hours on a Weekend Roster Agreement the Employer may request
              that the new Pharmacist delay the date of withdrawal and
              resumption of the new Pharmacist employee’s clause 55 roster. A
              new Pharmacist will advise the Employer of their response to a
              request made by their Employer under this sub clause as soon as
              possible after the request is made.
  (b)      In the event that a dispute arises regarding this Schedule, the Dispute
   Settling Procedure may be used in which a Pharmacist can be represented
   by the Union, any time this Schedule is being applied.
</code></pre></li></ol></li></ol><p>Attachment 1 Pharmacist Weekend Ordinary Hours Roster Agreement</p><p>Pharmacist Name: ……………………………………………………….. Employee No: …………………</p><p>Classification/Grade:……………………………………………………. Year Level: ………………………..</p><p>Employment Status: …………………………………………………. .Hours: ………………………………..</p><p>Service/Department: ……………………………………………………………………</p><p>I, the above named Pharmacist make this Agreement with my Employer following my request to commence working ordinary hours on weekends made in accordance with Schedule 13 of the Public Health Sector (Medical Scientists, Pharmacists &amp; Psychologists) Single Interest Enterprise Agreement 2021-2025. The agreed ordinary hours on weekends rostering arrangements details are as follows:</p><ol><li><p>Date of commencement: ……………………………………………………</p></li><li><p>Other details:</p></li></ol><p>Signed by the Employee Signed by the Employer</p><p>…………………………………….. …………………………………………………</p><p>Print Print Name:……………………………….. Name:……………………………………</p><p>Date: …………………………… Date:…………………………………………</p><p>Withdrawal from this Agreement: In accordance with clause 4 &amp; 5 of Schedule 13 I advise that I wish to withdraw from this Pharmacist Ordinary Hours on a Weekend Roster Agreement and hereby give 28 days notice of the effective date of my withdrawal.</p><p>Signed ………………………………………………………………..</p><p>Print Name ………………………………………………………….</p><p>Date…………………………………………………………. \`\`\`</p>`,40)])])}const u=t(i,[["render",r]]);export{m as __pageData,u as default};
